import { defineAgent } from "eve";

export default defineAgent({
  model: "openai/gpt-5.4-mini",
});

import { telegramChannel } from "eve/channels/telegram";

// Credentials come from env: TELEGRAM_BOT_TOKEN and
// TELEGRAM_WEBHOOK_SECRET_TOKEN. See SETUP.md.
export default telegramChannel();

import { mkdir, readFile, writeFile } from "node:fs/promises";
import path from "node:path";

export type UrlStatus = "up" | "down" | "unknown";

export type StatusSnapshot = {
  status: UrlStatus;
  checkedAt: string | null;
};

const STORE_PATH = path.join(process.cwd(), "var", "uptime-status.json");

export async function readLastStatus(): Promise<StatusSnapshot> {
  try {
    return JSON.parse(await readFile(STORE_PATH, "utf-8")) as StatusSnapshot;
  } catch {
    return { status: "unknown", checkedAt: null };
  }
}

export async function writeLastStatus(snapshot: StatusSnapshot): Promise<void> {
  await mkdir(path.dirname(STORE_PATH), { recursive: true });
  await writeFile(
    STORE_PATH,
    `${JSON.stringify(snapshot, null, 2)}\n`,
    "utf-8"
  );
}

import { defineSchedule } from "eve/schedules";

import telegram from "../channels/telegram";

// Every 5 minutes. CUSTOMIZE HERE if you want a different cadence.
export default defineSchedule({
  cron: "*/5 * * * *",
  async run({ receive, waitUntil, appAuth }) {
    const chatId = process.env.TELEGRAM_ALERT_CHAT_ID;
    if (!chatId) {
      console.warn("uptime-watch: TELEGRAM_ALERT_CHAT_ID is not set, skipping");
      return;
    }
    waitUntil(
      receive(telegram, {
        message:
          "Run an uptime check with check_url. Alert only if status changed.",
        target: { chatId },
        auth: appAuth,
      })
    );
  },
});

import { defineTool } from "eve/tools";
import { z } from "zod";

import {
  readLastStatus,
  writeLastStatus,
  type UrlStatus,
} from "../lib/status-store";

// CUSTOMIZE HERE: set UPTIME_WATCH_URL to the URL you want monitored.
const DEFAULT_URL = "https://example.com";
const TIMEOUT_MS = 10_000;

function classify(statusCode: number | null, ok: boolean): UrlStatus {
  if (!ok || statusCode === null) return "down";
  if (statusCode >= 200 && statusCode < 400) return "up";
  return "down";
}

export default defineTool({
  description:
    "Check the configured URL and return its current status plus whether it changed since the last check. Call this on every watch tick.",
  inputSchema: z.object({}),
  async execute(_input, ctx) {
    const url = process.env.UPTIME_WATCH_URL ?? DEFAULT_URL;
    const previous = await readLastStatus();
    const started = Date.now();

    let statusCode: number | null = null;
    let ok = false;
    let error: string | null = null;

    const controller = new AbortController();
    const timer = setTimeout(() => controller.abort(), TIMEOUT_MS);
    const onAbort = () => controller.abort();
    ctx.abortSignal.addEventListener("abort", onAbort);

    try {
      const response = await fetch(url, {
        method: "GET",
        redirect: "follow",
        signal: controller.signal,
      });
      statusCode = response.status;
      ok = response.ok;
    } catch (err) {
      error = err instanceof Error ? err.message : String(err);
      ok = false;
    } finally {
      clearTimeout(timer);
      ctx.abortSignal.removeEventListener("abort", onAbort);
    }

    const status = classify(statusCode, ok);
    const changed = previous.status !== "unknown" && previous.status !== status;
    const checkedAt = new Date().toISOString();

    await writeLastStatus({ status, checkedAt });

    return {
      url,
      status,
      previousStatus: previous.status,
      changed,
      statusCode,
      latencyMs: Date.now() - started,
      error,
      checkedAt,
    };
  },
});

import { defineEval } from "eve/evals";
import { includes } from "eve/evals/expect";

export default defineEval({
  description: "An on-demand check calls check_url and reports status.",
  async test(t) {
    await t.send(
      "Run an uptime check with check_url and tell me the current status."
    );
    t.succeeded();
    t.calledTool("check_url");
    t.check(t.reply, includes(/up|down|status/i)).soft();
  },
});

import { defineEvalConfig } from "eve/evals";

export default defineEvalConfig({
  maxConcurrency: 1,
  timeoutMs: 120_000,
});
